// Parse pesan dari WhatsApp Trigger
const data = $input.first().json;
const message = data.messages && data.messages[0];
const contact = data.contacts && data.contacts[0];
const metadata = data.metadata || {};

if (!message) return [{ json: { skip: true, reason: 'No message' } }];
if (message.type !== 'text') return [{ json: { skip: true, reason: 'Non-text: ' + message.type } }];

return [{
  json: {
    skip: false,
    messageId: message.id,
    from: message.from,
    clientName: contact && contact.profile ? contact.profile.name : 'Pelanggan',
    text: message.text && message.text.body ? message.text.body : '',
    timestamp: message.timestamp,
    phoneNumberId: metadata.phone_number_id || '1052743247932102',
    waBusinessId: metadata.display_phone_number || ''
  }
}];

// Build memory context untuk Groq
const messageData = $('Parse WA Message').first().json;
const rawHistory = $input.first().json;

// rawHistory bisa berupa array langsung atau wrapped object
const history = Array.isArray(rawHistory) ? rawHistory : (rawHistory.data || []);

// Reverse jadi chronological order (lama → baru), exclude pesan saat ini (yg baru aja di-save)
const chronological = history.slice().reverse();

// Format jadi chat history Groq (max 8 pesan supaya hemat token)
const chatHistory = chronological.slice(-8).map((m) => ({
  role: m.role === 'client' ? 'user' : 'assistant',
  content: m.content || ''
}));

// Build human-readable memory summary untuk dipass ke prompt
const memorySummary = chatHistory.length > 1
  ? '--- Percakapan sebelumnya ---\n' + chatHistory.slice(0, -1).map(m => (m.role === 'user' ? 'Customer: ' : 'Syifa: ') + m.content).join('\n')
  : '(Belum ada percakapan sebelumnya)';

return [{
  json: {
    ...messageData,
    chatHistory,
    memorySummary,
    historyCount: chronological.length
  }
}];

// Parse Groq output
const groqResponse = $input.first().json;
const raw = groqResponse?.choices?.[0]?.message?.content || '';

let classification;
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  classification = JSON.parse(cleaned);
} catch (e) {
  classification = {
    intent: 'OTHER',
    confidence: 0.3,
    extracted: {},
    needs_human: true,
    reason: 'Classifier parse failed: ' + e.message
  };
}

const messageData = $('Build Memory Context').first().json;

return [{
  json: {
    ...messageData,
    intent: classification.intent || 'OTHER',
    confidence: typeof classification.confidence === 'number' ? classification.confidence : 0.5,
    extracted: classification.extracted || {},
    needs_human: !!classification.needs_human,
    classifierReason: classification.reason || ''
  }
}];

// BUILD DECISION — Single source of truth untuk balasan WA Syifa
// Aturan emas: replyText TIDAK PERNAH null. Persona: Syifa.

const j = $json;
const rawName = (j.clientName || 'kak').toString().trim();
const name = rawName.split(' ')[0] || 'kak';

const intent = j.intent || 'OTHER';
const confidence = typeof j.confidence === 'number' ? j.confidence : 0.5;
const ext = j.extracted || {};
const explicitNeedsHuman = !!j.needs_human;

const needsHuman = explicitNeedsHuman || confidence < 0.45;

const pick = (arr) => arr[Math.floor(Math.random() * arr.length)];

let replyText = '';
let actionType = 'fallback';
let triggerEstimator = false;
let triggerProposal = false;

if (needsHuman) {
  replyText = 'Halo ' + name + ', aku Syifa dari Sudut Ruang. Pertanyaan kakak akan aku teruskan ke tim ya, mohon ditunggu sebentar 🙏';
  actionType = 'human';
} else if (intent === 'GREETING') {
  replyText = pick([
    'Halo ' + name + '! Aku Syifa, AI assistant dari Sudut Ruang ✨\n\nKita bantu desain arsitektur & interior untuk rumah, cafe, kantor, villa, dan lainnya.\n\nCeritain dulu proyek yang lagi kakak rencanain.',
    'Hai ' + name + '! Aku Syifa dari Sudut Ruang 👋\n\nKita spesialis jasa desain arsitektur & interior. Mau bangun atau renovasi apa nih?',
    'Halo ' + name + '! Syifa di sini, dari tim Sudut Ruang ✨\n\nBoleh share dulu kakak lagi rencanain proyek apa? (rumah/cafe/kantor/villa/lainnya)'
  ]);
  actionType = 'greeting';
} else if (intent === 'ASK_PRICE') {
  const hasType = !!ext.building_type;
  const hasArea = !!ext.area_sqm;
  if (hasType && hasArea) {
    replyText = 'Oke ' + name + ', Syifa lagi hitungin estimasi buat ' + ext.building_type + ' ' + ext.area_sqm + 'm². Tunggu sebentar ya, hasilnya aku kirim segera 📊';
    actionType = 'estimator';
    triggerEstimator = true;
  } else if (hasType) {
    replyText = 'Oke, desain ' + ext.building_type + ' ya. Aku Syifa, bantu kakak hitung estimasinya 😊\n\nBerapa luas areanya? (dalam m²)\n\nSama, kelas materialnya mau standar, menengah, atau premium?';
    actionType = 'collect_info';
  } else if (hasArea) {
    replyText = 'Noted ' + ext.area_sqm + 'm². Aku Syifa, bantu kakak hitung estimasinya ya 😊\n\nIni untuk apa ya? Rumah, cafe, kantor, villa, atau yang lain?';
    actionType = 'collect_info';
  } else {
    replyText = 'Halo ' + name + ', aku Syifa dari Sudut Ruang ✨\n\nBoleh ceritain dulu proyeknya:\n1. Jenis bangunan (rumah/cafe/kantor/villa/renovasi)\n2. Luas area (m²)\n3. Kelas material (standar/menengah/premium)\n\nBiar aku bisa kasih estimasi yang akurat.';
    actionType = 'collect_info';
  }
} else if (intent === 'REQUEST_PROPOSAL') {
  replyText = 'Siap ' + name + ', aku Syifa siapin proposal lengkapnya sekarang.\n\nProposal akan aku kirim ke WhatsApp ini dalam beberapa menit ya. Tunggu sebentar! 📋';
  actionType = 'proposal';
  triggerProposal = true;
} else if (intent === 'FOLLOW_UP') {
  replyText = 'Halo ' + name + ', Syifa di sini. Makasih udah follow up ya. Tim kita lagi cek dan bakal update kakak segera 🙌';
  actionType = 'human';
} else if (intent === 'GENERAL_QUESTION') {
  replyText = 'Halo ' + name + ', aku Syifa. Pertanyaan kakak udah aku catat. Tim kita akan jawab langsung biar lebih akurat ya, mohon ditunggu sebentar 🙏';
  actionType = 'human';
} else {
  replyText = 'Halo ' + name + '! Aku Syifa dari Sudut Ruang ✨\n\nBoleh ceritain lebih detail tentang proyeknya?\n• Jenis bangunan (rumah/cafe/kantor/villa)\n• Luas area\n• Lokasi';
  actionType = 'fallback';
}

return [{
  json: {
    ...j,
    replyText,
    actionType,
    triggerEstimator,
    triggerProposal,
    finalNeedsHuman: needsHuman
  }
}];

// GATE: hormati mode percakapan. Kalau operator sudah 'Take Over' (mode=manual),
// AI BERHENTI membalas. Customer message tetap tersimpan (sudah di-save di awal).
const j = $json;
const SUPABASE_URL = 'https://wbfqudrzwsnlzevxjlkm.supabase.co';
const ANON = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6IndiZnF1ZHJ6d3NubHpldnhqbGttIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzk2OTY2NjUsImV4cCI6MjA5NTI3MjY2NX0.6ceWsWJ2g9ilLdHvKgolh7rKt5X8JEQyBHwDEhGJ4lc';
let mode = 'ai';
try {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/conversations?id=eq.' + encodeURIComponent(j.from) + '&select=mode',
    headers: { apikey: ANON, Authorization: 'Bearer ' + ANON },
    json: true
  });
  if (Array.isArray(res) && res[0] && res[0].mode) mode = res[0].mode;
} catch (e) {
  // Kalau gagal cek mode, default tetap kirim (fail-open) supaya customer tidak ghosting.
  mode = 'ai';
}
if (mode === 'manual') {
  // Operator sedang menangani manual -> jangan balas otomatis.
  return [];
}
return [{ json: { ...j, conversationMode: mode } }];

